diff --git a/qemu_plugin/hybrid_handoff.c b/qemu_plugin/hybrid_handoff.c
index 50d43d7..2f38f40 100644
--- a/qemu_plugin/hybrid_handoff.c
+++ b/qemu_plugin/hybrid_handoff.c
@@ -105,6 +105,19 @@ static int      slice_consume_mode;
 static uint64_t slice_consume_acc;
 static uint64_t slice_consume_idx;

+// Drain-at-exit mode (F14): when drain_at_exit_mode is set (plugin arg
+// `drain_at_exit=1`), the plugin registers a per-insn exec callback that
+// bumps `atexit_insn_count`, and a `qemu_plugin_register_atexit_cb` that
+// drains state on natural program exit (e.g. semihosting EXIT). The
+// atexit callback overrides s.minstret with the plugin counter so the
+// caller (./hsim estimate --icount 0) gets a true retired-insn count
+// independent of QEMU's PMU semantics (which can return host ticks on
+// system-mode without `-icount`). `drained_already` suppresses the
+// atexit path if any other trigger (CSR/PC/icount/slice) drained first.
+static int      drain_at_exit_mode;
+static volatile int drained_already;
+static uint64_t atexit_insn_count;
+
 static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
 {
     for (guint i = 0; i < regs->len; i++) {
@@ -222,11 +235,15 @@ static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
     return 0;
 }

-static void on_handoff(unsigned int vcpu_idx, void *udata)
+// Drain CPU state to outfile_path. pc is computed by the caller (from a
+// HandoffSite for trigger paths, or 0 for the atexit path which lacks an
+// insn context). If minstret_override is non-zero, it replaces QEMU's PMU
+// minstret in the state file (used by drain_at_exit mode to record a
+// plugin-counted retired-insn total). Does NOT call exit -- caller
+// decides exit(200) (normal trigger) vs _exit(200) (inside atexit chain).
+static void drain_state_to_file(unsigned int vcpu_idx, uint64_t pc,
+                                uint64_t minstret_override)
 {
-    const HandoffSite *site = (const HandoffSite *) udata;
-    if (site->kind != HYBRID_HANDOFF_ENTER) return;
-
     VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
     resolve_handles(v);
     struct hybrid_state_v1 s = {0};
@@ -235,10 +252,7 @@ static void on_handoff(unsigned int vcpu_idx, void *udata)
     s.flags   = HYBRID_FLAG_RV64;
     s.hart_id = vcpu_idx;
     s.priv    = 3;
-    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
-    // exec callback can lag the actual current insn when V instructions
-    // retire just before the trigger (TCG defers PC writes for performance).
-    s.pc      = compute_handoff_pc(site);
+    s.pc      = pc;
     for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);

     // Floating-point: only set FP flag if at least one handle was bound,
@@ -261,7 +275,8 @@ static void on_handoff(unsigned int vcpu_idx, void *udata)
     s.mip      = read_reg64(v->mip);
     s.mie      = read_reg64(v->mie);
     s.mcycle   = read_reg64(v->mcycle);
-    s.minstret = read_reg64(v->minstret);
+    s.minstret = minstret_override ? minstret_override
+                                   : read_reg64(v->minstret);
     s.satp     = read_reg64(v->satp);

     for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
@@ -296,12 +311,52 @@ static void on_handoff(unsigned int vcpu_idx, void *udata)
     fprintf(stderr,
             "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
             outfile_path, s.pc);
+}
+
+static void on_handoff(unsigned int vcpu_idx, void *udata)
+{
+    const HandoffSite *site = (const HandoffSite *) udata;
+    if (site->kind != HYBRID_HANDOFF_ENTER) return;
+    // F14: suppress the atexit drain path now that we have a real trigger.
+    drained_already = 1;
+    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
+    // exec callback can lag the actual current insn when V instructions
+    // retire just before the trigger (TCG defers PC writes for performance).
+    drain_state_to_file(vcpu_idx, compute_handoff_pc(site), 0);
     // 200 == kExitHandoffToQemu in verilator/src/hybrid/exit_codes.hpp.
     // Distinguishes drain from workload completion (0) so the orchestrator
     // can decide the next spawn.
     exit(200);
 }

+// F14: per-insn tick. Increments a global counter every retired insn so the
+// drain-at-exit path can report a true retired-insn total (independent of
+// QEMU's PMU semantics).
+static void on_count_tick(unsigned int vcpu_idx, void *udata)
+{
+    (void) vcpu_idx;
+    (void) udata;
+    atexit_insn_count++;
+}
+
+// F14: atexit drain. Fires when QEMU exits naturally (e.g. guest semihosting
+// EXIT). The semihosting EXIT runs on the vCPU thread, so current_cpu is
+// still set and qemu_plugin_read_register works. If any other trigger
+// already drained, return immediately (drained_already guards against
+// double drain). Inside an atexit handler, exit() is UB per C11 7.22.4.4;
+// use _exit() to skip the rest of the atexit chain.
+static void on_atexit(qemu_plugin_id_t id, void *udata)
+{
+    (void) id;
+    (void) udata;
+    if (drained_already) return;
+    if (!drain_at_exit_mode) return;
+    // pc=0 is a positive marker that the atexit path drained (no trigger).
+    drain_state_to_file(0, 0, atexit_insn_count);
+    fflush(stderr);
+    _exit(200);
+}
+
 // Per-insn tick for icount mode. udata is the per-insn HandoffSite
 // pre-allocated at translation time, so on_handoff's compute_handoff_pc
 // returns the lag-free post-trigger PC (same property as the CSR path).
@@ -361,6 +416,14 @@ static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
     for (size_t i = 0; i < n; i++) {
         struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);

+        // F14 count tick: registered FIRST so the count is incremented
+        // before any trigger callback can call exit(200). NO_REGS keeps
+        // the per-insn cost minimal (a single uint64 add).
+        if (drain_at_exit_mode) {
+            qemu_plugin_register_vcpu_insn_exec_cb(
+                insn, on_count_tick, QEMU_PLUGIN_CB_NO_REGS, NULL);
+        }
+
         // BBV callback is registered BEFORE icount so that if both modes
         // fire on the same insn (icount target == slice multiple), the
         // slice row is emitted before exit(200) is called.
@@ -473,6 +536,18 @@ QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
             }
             slice_at_target = (uint64_t) v;
             slice_consume_mode = 1;
+        } else if (g_strcmp0(tok[0], "drain_at_exit") == 0 && tok[1]) {
+            // F14: any non-zero value enables. "1" is the canonical form
+            // hsim emits; other ints (incl. negatives parsed as huge unsigned)
+            // also enable -- the flag is a binary switch, not a count.
+            char *endp = NULL;
+            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
+            if (!endp || *endp != '\0') {
+                fprintf(stderr, "hybrid_handoff: invalid drain_at_exit=%s\n",
+                        tok[1]);
+                return -1;
+            }
+            drain_at_exit_mode = (v != 0);
         } else {
             fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
             return -1;
@@ -517,6 +592,10 @@ QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
                 " slice_at=%" PRIu64 "\n",
                 bbv_slice_target, slice_at_target);
     }
+    if (drain_at_exit_mode) {
+        fputs("hybrid_handoff: drain-at-exit mode enabled\n", stderr);
+        qemu_plugin_register_atexit_cb(id, on_atexit, NULL);
+    }

     vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
     qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);

=== USER_GUIDE Plugin Args Table (Section 2.3, around line 315) ===
| Plugin arg           | Effect                                                                 |
|----------------------|------------------------------------------------------------------------|
| `outfile=PATH`       | REQUIRED. Drained `hybrid_state_v1` is written here.                   |
| `enter_pc=0xADDR`    | M2: drain when PC == ADDR. Bypasses the CSR-insn matcher.              |
| `icount=N`           | M3: drain on the N-th retired insn (per vcpu).                         |
| `bbv_out=PATH`       | M4: emit one SimPoint BBV row per `slice=N` insns into PATH.           |
| `slice=N`            | Insns per slice (used by M4 and M5). Must be > 0.                      |
| `slice_at=K`         | M5: drain at the end of the K-th slice. Requires `slice=N`.            |


=== Plugin Code: drain_at_exit support (qemu_plugin/hybrid_handoff.c) ===
            }
            drain_at_exit_mode = (v != 0);
        } else {
            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
            return -1;
        }
    }
